// // This D flip-flop captures the value of the D input on the negative edge of the clock signal and outputs it on the Q output. If the reset signal is active (reset = 1), the Q output will remain unchanged.
module DFF (
	input clk,
	input reset,
	input D,
	output reg Q
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        Q <= 1'b0;
    end else begin
        Q <= D;
    end
end

endmodule
